/* Logical Text Alignment */
[dir="ltr"] .text-start { text-align: left; }
[dir="rtl"] .text-start { text-align: right; }
[dir="ltr"] .text-end { text-align: right; }
[dir="rtl"] .text-end { text-align: left; }

/* Flexbox Direction Utilities */
[dir="ltr"] .flex-row-start { flex-direction: row; }
[dir="rtl"] .flex-row-start { flex-direction: row-reverse; }
[dir="ltr"] .flex-row-end { flex-direction: row-reverse; }
