}
[dir="rtl"] .rtl-flip {
  transform: scaleX(-1);
}

/* Text and Content Responsiveness Utilities */
.responsive-text {
  word-wrap: break-word;
  overflow-wrap: break-word;
  hyphens: auto;
  -webkit-hyphens: auto;
  -ms-hyphens: auto;
}

.text-safe {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.text-wrap-safe {
  min-width: 0;
  word-break: break-word;
  overflow-wrap: break-word;
  white-space: normal;
}

.line-clamp-safe {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  word-break: break-word;
}

/* Container Responsiveness */
.container-safe {
  min-width: 0;
  width: 100%;
  max-width: 100%;
  overflow: hidden;
}

.flex-safe {
  min-width: 0;
  flex-shrink: 1;
}

/* Grid Responsiveness */
.grid-responsive {
  display: grid;
