/**
 * Product Migration Validation Utility
 * 
 * This utility validates that the pilot product migration is working correctly
 * by checking the adapter functionality for our 5 pilot products.
 * 
 * Note: This utility can be run within the Vite/TS environment or manually tested
 * by calling the adapter functions directly in the browser console.
 */

// Placeholder imports - these would be replaced with actual imports in a TS environment
// import { getProductDetailBySlug, getAllProductSlugs } from './client/src/data/products-detail-pages-data.ts';

// Pilot products to validate
const PILOT_PRODUCTS = [
  'bldc-smart-ceiling-fan-1200',
  'bldc-premium-ceiling-fan-1400', 
  'bldc-commercial-ceiling-fan-1500',
  'solar-bldc-submersible-pump-1hp',
  'instrumentation-cables'
];

// Mock translation function for testing
const mockT = (key, options = {}) => {
  const { defaultValue, returnObjects } = options;

  // Simulate English translations being available
  const translations = {
    // Mock some basic products-data translations
    'products-data:bldc-smart1200.seo.title': 'BLDC Smart Ceiling Fan 1200 RPM - Energy Efficient | Powerton Engineering',
    'products-data:bldc-smart1200.hero.title': 'BLDC Smart Ceiling Fan 1200 RPM',
    'products-data:bldc-premium1400.seo.title': 'BLDC Premium Ceiling Fan 1400 RPM - Advanced Features | Powerton Engineering',
    'products-data:labels.power': 'Motor Power',
    'products-data:labels.speed': 'Speed Rating',
    'products-data:labels.airflow': 'Air Flow',
    'products:categories.bldc.title': 'BLDC Products',
    'products:subcategories.bldc-ceiling-fan.title': 'BLDC Ceiling Fans',
    'common:buttons.downloadGuide': 'Download Guide'
  };

  if (returnObjects && Array.isArray(defaultValue)) {
    return defaultValue; // Return the default array
  }

  return translations[key] || defaultValue || key;
};

function validateProduct(slug) {
  console.log(`\n=== Validating Product: ${slug} ===`);

  try {
    const productData = getProductDetailBySlug(slug, mockT);

    if (!productData) {
      console.error(`❌ Product not found: ${slug}`);
      return false;
    }

    console.log(`✅ Product found: ${productData.id}`);

    // Check required fields
    const requiredFields = ['id', 'title', 'shortDescription', 'image', 'seo', 'specifications', 'keyBenefits', 'features'];
    let allFieldsValid = true;

    for (const field of requiredFields) {
      if (!productData[field]) {
        console.error(`❌ Missing required field: ${field}`);
        allFieldsValid = false;
      } else {
        console.log(`✅ ${field}: OK`);
      }
    }

    // Check SEO fields
    if (productData.seo) {
      const seoFields = ['title', 'description', 'keywords', 'canonicalUrl'];
      for (const field of seoFields) {
        if (!productData.seo[field]) {
          console.error(`❌ Missing SEO field: ${field}`);
          allFieldsValid = false;
        } else {
          console.log(`✅ SEO ${field}: OK`);
        }
      }
    }

    // Check specifications format
    if (productData.specifications && Array.isArray(productData.specifications)) {
      console.log(`✅ Specifications array: ${productData.specifications.length} items`);
      productData.specifications.forEach((spec, index) => {
        if (!spec.label || !spec.value) {
          console.error(`❌ Invalid specification at index ${index}:`, spec);
          allFieldsValid = false;
        }
      });
    }

    return allFieldsValid;

  } catch (error) {
    console.error(`❌ Error validating ${slug}:`, error.message);
    return false;
  }
}

function runValidation() {
  console.log('🔍 Starting Product Migration Validation');
  console.log('='.repeat(50));

  let totalProducts = 0;
  let validProducts = 0;

  for (const slug of PILOT_PRODUCTS) {
    totalProducts++;
    if (validateProduct(slug)) {
      validProducts++;
    }
  }

  console.log('\n' + '='.repeat(50));
  console.log(`📊 Validation Summary:`);
  console.log(`Total Products: ${totalProducts}`);
  console.log(`Valid Products: ${validProducts}`);
  console.log(`Success Rate: ${((validProducts / totalProducts) * 100).toFixed(1)}%`);

  if (validProducts === totalProducts) {
    console.log('🎉 All pilot products are valid! Migration ready for testing.');
  } else {
    console.log('⚠️  Some products have issues. Please review and fix before proceeding.');
  }

  return validProducts === totalProducts;
}

// Export for use
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { runValidation, validateProduct, PILOT_PRODUCTS };
}

// Run validation if executed directly
if (typeof window === 'undefined' && require.main === module) {
  runValidation();
}

